  'anqing/sail': ('안칭 항구', '\'평화로운 축하\'라는 뜻을 가진 안후이성의 양쯔강 주요 항구 도시예요.'),
  'ganzhou/orange': ('간난 네이블 오렌지', '붉은 토양에서 자라 중국에서 가장 달콤하기로 유명한 네이블 오렌지예요.'),
  'ganzhou/house': ('객가 토루', '객가 사람들은 수 세기 동안 독특한 원형 요새 주택인 토루에서 살아왔어요.'),
  'ganzhou/pavilion': ('위구정', '송나라 시인들이 노래했던 이 정자는 강줄기가 갈라지는 풍경을 한눈에 내려다볼 수 있어요.'),
  'ganzhou/star': ('대장정', '중국 홍군의 대장정이 바로 이 도시에서 시작되었어요.'),
  'putian/shrine': ('마조묘', '뱃사람의 수호신인 마조 여신이 태어난 곳으로, 메이저우섬에 본당이 자리하고 있어요.'),
  'putian/lychee': ('리치 과수원', '천 년 된 리치 나무들이 가득해 이 도시는 \'리치의 고장\'이라는 별명을 얻었어요.'),
  'putian/shoe': ('신발의 도시', '전 세계 스포츠화의 상당 부분이 이곳의 공장에서 생산되고 있어요.'),
  'putian/wave': ('메이저우섬', '페리를 타고 들어갈 수 있는 이 섬은 아름다운 해변과 사원 축제로 유명해요.'),
  'mudanjiang/snow': ('중국 설향', '겨울이면 두꺼운 눈이 덮여 동화 속 마을처럼 빛나는 곳이에요.'),
  'mudanjiang/lake': ('징포호', '화산 활동으로 생긴 호수로, 겨울에도 댜오수이러우 폭포가 웅장하게 쏟아져요.'),
  'mudanjiang/tiger': ('시베리아 호랑이 공원', '세계에서 가장 큰 시베리아 호랑이 보호구역 중 하나예요.'),
  'mudanjiang/ski': ('스키 시즌', '눈이 길게 내리는 겨울 덕분에 스키어들에게는 꼭 가봐야 할 명소로 꼽혀요.'),
  'changzhou/dino': ('공룡원', '중국에서 가장 유명한 공룡 테마파크로, 가족 단위 여행객에게 인기가 많아요.'),
  'changzhou/pagoda': ('톈닝사 탑', '높이 153미터에 달하는 세계에서 가장 높은 탑이 도심 한가운데 솟아 있어요.'),
  'changzhou/comb': ('빗 공예', '천 년의 역사를 자랑하는 창저우의 빗은 과거 왕실에 진상되던 귀한 선물이었어요.'),
  'changzhou/canal': ('대운하', '운하를 따라 걸으며 옛 거리의 정취와 화려한 야경을 즐길 수 있어요.'),
  'shaoxing/wine': ('사오싱주', '중국 요리에 빠지지 않는 유명한 황주가 수천 년 동안 이곳에서 빚어져 왔어요.'),
  'shaoxing/bridge': ('석교', '운하가 발달한 사오싱에는 수백 개의 고풍스러운 아치형 돌다리가 남아 있어요.'),
  'shaoxing/pen': ('서예의 성지', '서예가 왕희지의 난정서가 탄생한 이곳은 서예를 공부하는 사람들에게 성지와 같아요.'),
  'shaoxing/boat': ('우펑선', '발로 노를 저어 움직이는 검은 지붕의 우펑선은 운하를 여행하는 가장 고전적인 방법이에요.'),
  'bengbu/shell': ('진주의 항구', '지명 자체가 \'조개 부두\'라는 뜻으로, 과거 화이허강의 진주로 명성이 높았어요.'),
  'bengbu/train': ('철도 교통의 요충지', '남북을 잇는 철도 노선이 화이허 강을 건너는 곳으로, 벵부라는 도시는 이 역을 중심으로 성장했습니다.'),
  'bengbu/river': ('화이허 강', '중국의 남북을 가르는 기준이 되는 화이허 강이 이곳을 유유히 흐릅니다.'),
  'bengbu/blossom': ('봄꽃 축제', '매년 봄이 되면 강변 공원마다 화사한 꽃들이 만개하여 축제가 열립니다.'),
  'jiujiang/mountain': ('루산', '유네스코 세계유산으로 등재된 루산은 안개 낀 절경으로 수많은 시인과 화가들에게 영감을 주었습니다.'),
  'jiujiang/tea': ('윈우차', '루산의 비탈에서 재배되는 윈우차는 중국에서 가장 섬세한 맛을 자랑하는 차 중 하나입니다.'),
  'jiujiang/lake': ('포양호', '중국 최대의 담수호인 포양호는 겨울철이 되면 수천 마리의 두루미가 찾아오는 철새 도래지입니다.'),
  'jiujiang/scroll': ('시의 도시', '백거이와 소식 같은 대문호들이 이곳 강변에서 아름다운 시 구절을 남겼습니다.'),
  'quanzhou/ship': ('해상 실크로드', '마르코 폴로가 \'자이툰\'이라 불렀던 이곳은 중세 시대 세계 최대의 항구였으며 유네스코 세계유산으로 지정되었습니다.'),
  'quanzhou/mosque': ('칭징사', '1009년에 세워진 이 돌로 만든 이슬람 사원은 중국에서 가장 오래된 사원 중 하나입니다.'),
  'quanzhou/puppet': ('꼭두각시 인형극', '취안저우의 줄 인형극은 천 년의 역사를 이어온 전통 공연 예술입니다.'),
  'quanzhou/tea': ('철관음', '인근 안시 지역에서 생산되는 우롱차인 철관음은 세계적으로 유명한 명차입니다.'),
  'shanghai/pearl': ('동방명주', '황푸강 위로 솟아오른 분홍색 구체 모양의 이 탑은 현대 상하이를 상징하는 랜드마크입니다.'),
  'shanghai/bund': ('와이탄', '강변을 따라 늘어선 고풍스러운 건축물들은 옛 상하이의 화려했던 시절을 보여줍니다.'),
  'shanghai/garden': ('예원', '명나라 시대에 조성된 전통 정원으로, 도심 속에서 아름다운 바위와 연못을 즐길 수 있는 휴식처입니다.'),
  'shanghai/xlb': ('샤오룽바오', '뜨거운 육즙이 가득한 샤오룽바오는 상하이 아침 식사를 대표하는 최고의 별미입니다.'),
  'hangzhou/lake': ('시후', '버드나무와 작은 섬, 아치형 다리가 어우러진 시후는 중국 시인들에게 가장 많은 찬사를 받은 호수예요.'),
  'hangzhou/tea': ('롱징차', '호수 주변 비탈에서 재배되는 \'용정차\'는 중국에서 가장 유명한 녹차예요.'),
  'hangzhou/temple': ('링인사', '1,700년의 역사를 자랑하는 링인사는 정교한 암벽 조각과 거대한 불상으로 유명해요.'),
  'hangzhou/silk': ('실크 시티', '천 년의 역사를 지닌 항저우의 비단은 실크로드 동쪽 끝을 풍요롭게 만들었던 귀한 특산물이에요.'),
  'chongqing/hongya': ('훙야둥', '절벽을 따라 지어진 훙야둥은 밤이 되면 강 위로 동화 속 풍경처럼 화려하게 빛나요.'),
  'chongqing/hotpot': ('충칭 훠궈', '얼얼하고 매콤한 기름이 끓어오르는 훠궈는 산악 도시 충칭의 뜨거운 영혼과도 같아요.'),
  'chongqing/monorail': ('충칭 모노레일', '건물 사이를 통과하는 모노레일은 언덕 위에 세워진 충칭만의 독특한 풍경이에요.'),
  'chongqing/river': ('양쯔강 싼샤', '두 강이 만나는 지점에 위치한 충칭 항구에서는 양쯔강 싼샤를 둘러보는 유람선이 출발해요.'),
  'dalian/square': ('싱하이 광장', '아시아에서 가장 큰 도시 광장인 싱하이 광장에서는 바닷바람을 맞으며 다양한 축제와 공연이 열려요.'),
  'dalian/beach': ('다롄 해변', '바위가 어우러진 해안과 시원한 여름 날씨 덕분에 다롄은 중국 북부에서 가장 사랑받는 휴양지예요.'),
  'dalian/football': ('축구 도시', '중국 축구의 요람이라 불리는 다롄은 수많은 명문 구단을 배출한 도시예요.'),
  'dalian/seafood': ('해산물 요리', '차가운 황해에서 잡은 가리비, 새우, 성게 등 신선한 해산물이 다롄의 식탁을 풍성하게 채워줘요.'),
  'shenyang/palace': ('선양 고궁', '청나라의 첫 번째 궁궐로, 베이징 자금성의 축소판이라 할 수 있는 역사적인 장소예요.'),
  'shenyang/tomb': ('청나라 황릉', '선양 외곽을 둘러싼 동릉과 북릉은 청나라를 세운 황제들의 웅장한 무덤이에요.'),
  'shenyang/factory': ('산업의 요람', '중국 중공업의 발상지인 선양은 거대한 공장들이 밀집해 있어 \'동양의 루르\'라고도 불려요.'),
  'shenyang/dumpling': ('라오볜 만두', '200년의 역사를 자랑하는 라오볜 만두는 북방 요리를 대표하는 별미예요.'),
  'hefei/judge': ('포공사', '청렴한 판관으로 유명한 포청천의 고향인 이곳에는 그의 정신을 기리는 사당이 있어요.'),
  'hefei/science': ('과학 도시', '중국을 대표하는 주요 대학과 연구소들이 모여 있는 첨단 기술의 중심지예요.'),
  'hefei/lake': ('차오후', '중국 5대 담수호 중 하나로, 맛 좋은 백어와 게가 나기로 유명해요.'),
  'hefei/cake': ('루저우 참깨떡', '달콤한 소가 들어간 참깨떡은 옛 루저우 지역에서 오랫동안 사랑받아 온 간식이에요.'),
  'foshan/wingchun': ('영춘권', '엽문과 이소룡의 무술 뿌리인 영춘권의 본고장이에요.'),
  'foshan/lion': ('사자춤', '남부 사자춤의 수도라 불리며, 화려한 사자들이 기둥 위를 넘나드는 모습이 장관이에요.'),
  'foshan/ceramic': ('스완 도자기', '천 년의 역사를 지닌 가마에서 생동감 넘치는 스완 도자기 인형들이 지금도 만들어지고 있어요.'),
  'foshan/opera': ('광둥 오페라', '중국 남부에서 가장 사랑받는 무대 예술인 광둥 오페라가 이곳에서 꽃피웠어요.'),
  'guiyang/pavilion': ('자슈러우', '난밍강 위에 세워진 3층 누각으로, 400년 동안 구이양을 상징해 온 랜드마크예요.'),
  'guiyang/sourfish': ('쏸탕위', '발효된 토마토로 만든 새콤한 붉은 국물에 생선을 넣고 끓인 구이저우의 대표 요리예요.'),
  'guiyang/waterfall': ('황궈수 폭포', '아시아 최대 규모의 폭포 중 하나로, 웅장한 물줄기와 함께 무지개가 피어오르는 절경을 볼 수 있어요.'),
  'guiyang/miao': ('묘족 문화', '은 장식을 머리에 쓴 묘족의 축제와 화려한 자수는 산간 마을을 더욱 아름답게 만들어요.'),
  'changchun/film': ('영화 도시', '중국 영화의 발상지이자 \'동양의 할리우드\'라 불리는 영화 촬영소가 이곳에 있어요.'),
  'changchun/car': ('자동차 도시', '중국 최초의 국산 자동차가 탄생한 곳으로, 명실상부한 중국 자동차 산업의 중심지예요.'),
  'changchun/palace': ('위만황궁', '마지막 황제가 머물렀던 이 궁궐은 격동의 역사를 고스란히 간직하고 있어요.'),
  'changchun/snow': ('겨울 눈', '길고 하얀 겨울이 찾아오면 도시는 얼음 조각과 스키장으로 반짝여요.'),
  'xining/lake': ('칭하이호', '중국 최대의 염호로, 여름이면 호수 주변을 가득 채우는 유채꽃밭으로 유명해요.'),
  'xining/monastery': ('타르사', '티베트 불교 6대 사원 중 하나로, 야크 버터로 만든 정교한 조각상이 특히 잘 알려져 있어요.'),
  'xining/flower': ('유채꽃', '7월이 되면 고원 지대는 지평선 끝까지 황금빛 유채꽃으로 뒤덮여 장관을 이뤄요.'),
  'xining/lamb': ('야크와 양고기', '후이족과 티베트족의 손맛이 담긴 수타면과 양꼬치는 이 고원 지대를 대표하는 별미예요.'),
  'guilin/karst': ('리강 카르스트 지형', '안개 속으로 솟아오른 석회암 봉우리들은 20위안 지폐 뒷면에도 그려진 절경이에요.'),
  'guilin/elephant': ('상비산', '강물에 코를 담그고 있는 코끼리 모양의 바위는 구이린을 상징하는 사랑받는 명소예요.'),
  'guilin/terrace': ('룽지 다랭이논', '용의 등뼈를 닮았다고 해서 이름 붙여진 이 계단식 논은 수 세기 동안 이어진 땀과 노력의 결실이에요.'),
  'guilin/osmanthus': ('계화꽃', '도시 이름에 \'계수나무 숲\'이라는 뜻이 담겨 있듯, 가을이면 도시 전체가 달콤한 꽃향기로 가득 차요.'),
  'wenzhou/merchant': ('원저우 상인 정신', '중국의 유대인이라 불리는 원저우 기업가들은 전 세계를 무대로 비즈니스 네트워크를 구축하고 있어요.'),
  'wenzhou/shoe': ('신발과 가죽', '전 세계 가죽 신발의 상당수가 바로 이 제조 도시인 원저우에서 생산돼요.'),
  'wenzhou/mountain': ('옌당산', '폭포와 험준한 봉우리로 유명하며, \'바다 옆 제일가는 산\'이라는 찬사를 받는 곳이에요.'),
  'wenzhou/seafood': ('해산물', '동중국해에서 갓 잡아 올린 오징어, 가리비, 생선은 이곳 식탁을 책임지는 주재료예요.'),
  'tangshan/memorial': ('지진 기념비', '1976년 대지진을 기리는 이 기념 공원은 다시 태어난 도시의 상징과도 같아요.'),
  'tangshan/coal': ('탕산 탄광', '중국 최초의 근대식 탄광과 철도가 시작된 이곳은 중국 산업의 발상지입니다.'),
  'tangshan/ceramic': ('탕산 도자기', '북방의 도자기 도시로 불리는 이곳의 본차이나는 우아한 품질로 유명합니다.'),
  'tangshan/lake': ('난후 공원', '과거 채굴장이었던 곳을 공원으로 탈바꿈시켜 도시의 녹색 허파 역할을 하고 있습니다.'),
  'anshan/steel': ('철강 도시', '중국 최대 규모의 제철소가 설립된 이곳은 명실상부한 중국의 철강 수도입니다.'),
  'anshan/jade': ('슈옌 옥', '세계 최대 규모의 옥 조각품이 있는 이곳은 중국을 대표하는 옥의 고장입니다.'),
  'anshan/mountain': ('첸산', '천 개의 연꽃 봉우리가 솟아 있다는 첸산은 사찰과 기암괴석이 어우러진 북방의 명산입니다.'),
  'anshan/spring': ('탕강쯔 온천', '천 년의 역사를 자랑하는 이곳 온천은 예로부터 황제들이 즐겨 찾던 치유의 명소입니다.'),
  'linyi/market': ('도매 시장', '중국 북부 최대 규모의 도매 허브로, 이곳의 물류는 전국 각지로 뻗어 나갑니다.'),
  'linyi/brush': ('왕희지 생가', '서예의 성인이라 불리는 왕희지가 태어난 이곳은 먹과 붓의 향기가 가득한 도시입니다.'),
  'linyi/mountain': ('멍산', '산둥성에서 두 번째로 높은 멍산은 맑은 공기와 폭포가 어우러진 천연 산소 카페와 같습니다.'),
  'linyi/pancake': ('이멍 지엔빙', '옥수수로 얇게 부쳐낸 지엔빙은 이멍 산간 지역 사람들이 오랫동안 즐겨 먹어온 주식입니다.'),
  'cangzhou/lion': ('철사자', '1,100년의 역사를 간직한 거대한 철제 사자상은 창저우를 상징하는 자랑스러운 문화유산입니다.'),
  'cangzhou/martial': ('무술의 고향', '중국 무술의 본고장으로 불리는 이곳은 수많은 무술 대가와 문파를 배출했습니다.'),
  'cangzhou/canal': ('대운하', '베이징과 항저우를 잇는 대운하가 도시를 가로지르며, 옛 부두의 정취를 그대로 간직하고 있습니다.'),
  'cangzhou/jujube': ('금사 대추', '껍질이 얇고 달콤한 금사 대추는 건과일 중에서도 으뜸으로 꼽힙니다.'),
  'nantong/textile': ('난퉁 방직성', '중국 가정용 섬유의 중심지로, 이곳에서 생산된 면직물은 전 세계로 수출되고 있어요.'),
  'nantong/mountain': ('랑산', '양쯔강 하구에 솟아 있는 다섯 개의 봉우리를 가진 성스러운 산으로, 많은 순례객과 관광객이 찾아요.'),
  'nantong/kite': ('반야오 연', '연에 피리를 달아 소리가 나게 만든 \'반야오\'는 난퉁의 오랜 전통 공예품이에요.'),
  'nantong/school': ('근대 교육의 발상지', '산업가 장젠이 이곳에 중국 최초의 근대식 학교와 박물관을 설립했어요.'),
  'taizhou/opera': ('메이란팡', '경극의 전설적인 거장 메이란팡의 고향으로 유명한 도시예요.'),
  'taizhou/tea': ('자오차', '아침에 찐빵과 차를 곁들여 먹는 \'자오차\'는 타이저우 사람들의 일상적인 아침 식사 문화예요.'),
  'taizhou/boat': ('친퉁 보트 축제', '봄이 되면 수백 명의 노잡이가 참여하는 보트 경주가 열려 강 위를 활기차게 만들어요.'),
  'taizhou/meatball': ('사자두', '크고 부드러운 돼지고기 완자인 \'사자두\'는 화이양 요리를 대표하는 고전적인 음식이에요.'),
  'jinhua/ham': ('진화 햄', '수백 년 전통의 방식으로 염장한 붉은 빛의 진화 햄은 중국에서 가장 유명한 햄이에요.'),
  'jinhua/film': ('헝뎬 스튜디오', '세계 최대 규모의 야외 촬영지로, 수많은 시대극이 이곳에서 제작되고 있어요.'),
  'jinhua/cave': ('솽룽 동굴', '낮은 바위 문을 지나 배를 타고 들어가는 지하 동굴의 풍경은 감탄을 자아내요.'),
  'jinhua/bridge': ('고대 석교', '아치형 돌다리와 물길이 어우러진 마을에서 강남 지역 특유의 우아함을 느낄 수 있어요.'),
  'wuhu/park': ('팡터 원더랜드', '중국 최대 규모의 테마파크 중 하나로, 가족 단위 방문객들에게 즐거운 추억을 선사해요.'),
  'wuhu/ironart': ('철화', '연철을 두드려 만든 우아한 \'철화\'는 300년의 역사를 자랑하는 전통 공예예요.'),
  'wuhu/rice': ('미시', '양쯔강 변에 위치한 이 도시는 역사적으로 중국 최대의 쌀 시장이었어요.'),
  'wuhu/river': ('양쯔강 항구', '분주한 강 항구가 있어 안후이성의 바닷길 관문 역할을 하는 도시예요.'),
  'huangshan/peak': ('황산', '화강암 봉우리와 운해, 기묘한 소나무가 어우러진 중국에서 가장 유명한 산이에요.'),
  'huangshan/village': ('훙춘 마을', '물길과 하얀 벽이 어우러진 유네스코 세계문화유산 마을로, 마치 한 폭의 그림 같아요.'),
  'huangshan/tea': ('황산모봉', '안개 낀 산비탈에서 채취한 솜털 덮인 녹차로, 중국 10대 명차 중 하나예요.'),
  'huangshan/ink': ('휘주 먹과 예술', '휘주 지역의 먹과 목조 가옥, 서예는 이 지역의 소중한 문화적 자산이에요.'),
  'yichun/moon': ('밍웨산', '밝은 달이라는 뜻의 밍웨산은 온천과 케이블카에서 내려다보는 풍경으로 유명해요.'),
  'yichun/spring': ('온천', '희귀한 셀레늄이 풍부한 온천 덕분에 중국의 대표적인 온천 휴양지로 자리 잡았어요.'),
  'yichun/zen': ('선불교', '중국 선불교의 뿌리를 둔 산속 사찰들이 마음의 평온을 찾아줘요.'),
  'yichun/rice': ('곡창지대', '비옥한 위안허 평야는 예로부터 장시성의 곡창지대 역할을 해왔어요.'),
  'zhangzhou/narcissus': ('수선화', '중국에서 가장 유명한 수선화가 자라는 곳으로, 봄 축제의 상징이기도 해요.'),
  'zhangzhou/tulou': ('객가 토루', '유네스코 세계문화유산인 거대한 원형 흙집으로, 마을 사람들이 한 지붕 아래 모여 살아요.'),
  'zhangzhou/banana': ('열대 과일', '바나나, 용안, 귤 과수원 덕분에 따뜻한 삼각주 지역은 일 년 내내 푸르러요.'),
  'zhangzhou/coast': ('둥산섬', '황금빛 해변과 어촌 마을이 어우러진 이곳은 남부 해안의 진주라고 불려요.'),
  'guangzhou/tower': ('광저우 타워', '세계에서 가장 높은 타워 중 하나인 \'샤오만야오\'는 밤마다 화려한 빛으로 도시를 수놓아요.'),
  'guangzhou/dimsum': ('얌차', '대나무 찜기에 찐 딤섬을 차와 함께 즐기는 \'얌차\'는 광둥 식문화의 핵심이에요.'),
  'guangzhou/academy': ('천씨서원', '정교한 목조각과 도자기 장식으로 유명한 이곳은 광둥 건축 예술의 걸작으로 꼽혀요.'),
  'guangzhou/flower': ('꽃의 도시', '일 년 내내 꽃이 피는 광저우는 매년 설날마다 대규모 꽃 시장이 열려 \'꽃의 도시\'라고 불려요.'),
  'wuhan/crane': ('황학루', '양쯔강을 내려다보는 천 년 역사의 이 누각은 중국의 수많은 명시를 탄생시킨 영감의 원천이에요.'),
  'wuhan/noodle': ('러간몐', '고소한 참깨 소스를 듬뿍 얹은 러간몐은 우한 사람들에게 없어서는 안 될 아침 식사예요.'),
  'wuhan/duckneck': ('야보즈', '매콤하게 졸여낸 오리 목 요리인 야보즈는 우한 사람들이 야식으로 즐겨 찾는 대표 간식이에요.'),
  'wuhan/university': ('우한대학교 벚꽃', '봄이 되면 우한대학교의 아름다운 벚꽃을 보기 위해 수많은 방문객이 몰려들어요.'),
  'tianjin/eye': ('톈진 아이', '다리 위에 세워진 거대한 관람차로, 강 양쪽의 풍경을 한눈에 내려다볼 수 있어요.'),
  'tianjin/baozi': ('거우부리 만두', '주름이 잡힌 육즙 가득한 돼지고기 만두로, 150년 전통을 자랑하는 톈진의 명물이에요.'),
  'tianjin/crosstalk': ('샹성', '두 사람이 주고받는 만담인 샹성은 톈진의 찻집 문화에서 시작된 전통 공연 예술이에요.'),
  'tianjin/architecture': ('우다다오', '유럽식 저택이 모여 있는 우다다오는 \'건축 박물관\'이라 불릴 만큼 이국적인 풍경을 자랑해요.'),
  'xiamen/island': ('구랑위', '차 없는 거리와 고풍스러운 유럽식 저택이 어우러진 구랑위는 유네스코 세계문화유산으로 지정된 섬이에요.'),
  'xiamen/piano': ('피아노의 섬', '인구 대비 피아노 보유율이 매우 높은 구랑위는 \'피아노의 섬\'이라는 별칭으로 유명해요.'),
  'xiamen/egret': ('백로', '샤먼의 상징인 백로는 과거 이 도시가 \'백로의 섬\'이라 불렸던 것에서 유래했어요.'),
  'xiamen/oyster': ('굴전', '신선한 굴과 달걀을 넣어 바삭하게 부쳐낸 굴전은 샤먼 해안 지역의 대표적인 별미예요.'),
  'harbin/ice': ('하얼빈 빙등제', '겨울마다 거대한 얼음 궁전이 화려한 조명과 함께 펼쳐지는 세계 최대 규모의 축제예요.'),
  'harbin/cathedral': ('성 소피아 성당', '양파 모양의 돔이 특징인 이 러시아 정교회 성당은 하얼빈의 유럽풍 역사를 상징하는 랜드마크예요.'),
  'harbin/sausage': ('홍창(하얼빈 소시지)', '러시아식으로 훈제한 붉은색 소시지는 하얼빈에서 100년 넘게 사랑받아 온 별미예요.'),
  'harbin/accordion': ('음악의 도시', '러시아 문화의 영향을 깊게 받은 하얼빈은 중국 최초의 교향악단이 탄생한 음악의 도시예요.'),
  'fuzhou/alley': ('싼팡치샹', '흰 벽과 검은 기와가 어우러진 이 옛 거리는 명·청 시대 건축 양식을 그대로 간직한 살아있는 박물관이에요.'),
  'fuzhou/banyan': ('용의 도시', '거대한 고목들이 거리 곳곳에 그늘을 드리우고 있어 푸저우는 \'용의 도시\'라고도 불려요.'),
  'fuzhou/hotspring': ('온천', '도심 곳곳에서 솟아나는 온천수는 천 년 넘게 푸저우 시민들의 목욕 문화와 함께해 왔어요.'),
  'fuzhou/soup': ('불도장', '수십 가지 귀한 재료를 푹 고아 만든 이 고급 요리는 푸젠 요리의 정수로 꼽혀요.'),
  'dongguan/robot': ('세계의 공장', '자동화된 공장이 밀집한 둥관은 전 세계 전자제품의 상당 부분을 생산하고 있어요.'),
  'dongguan/basketball': ('농구의 도시', '중국에서 가장 화려한 수상 경력을 자랑하는 농구 클럽이 바로 이 \'농구의 도시\' 둥관을 연고지로 하고 있어요.'),
  'dongguan/keyuan': ('커위안', '연못과 정자가 아름답기로 유명한 이곳은 광둥성의 4대 명원 중 하나예요.'),
  'dongguan/cannon': ('후먼 포대', '아편 전쟁의 시발점이 된 후먼 포대는 당시 아편을 불태웠던 역사의 현장이에요.'),
  'lanzhou/beefnoodle': ('란저우 우육면', '맑은 소고기 육수와 직접 뽑은 면발을 자랑하는 란저우는 중국 면 요리의 중심지예요.'),
  'lanzhou/waterwheel': ('수차', '황하 강변에 자리한 거대한 수차는 수백 년간 이어져 온 관개 기술의 역사를 상징해요.'),
  'lanzhou/statue': ('황하 어머니상', '강변에 세워진 어머니와 아이의 동상은 중국 문명을 길러낸 황하를 상징하고 있어요.'),
  'lanzhou/raft': ('양가죽 뗏목', '양가죽에 바람을 넣어 만든 전통 뗏목은 지금도 황하 위를 유유히 떠다니고 있어요.'),
  'urumqi/bazaar': ('국제대바자', '이슬람풍의 첨탑과 향신료 가게들이 어우러진 바자르에서 실크로드의 다채로운 색감을 느낄 수 있어요.'),
  'urumqi/tianshan': ('천지', '천산의 만년설 아래 자리 잡은 천지는 울창한 가문비나무 숲으로 둘러싸여 있어 절경을 자랑해요.'),
  'urumqi/kebab': ('양꼬치', '숯불에 구워 향신료를 뿌린 양꼬치는 위구르 식탁에서 빠질 수 없는 대표적인 요리예요.'),
  'urumqi/dance': ('위구르 전통춤', '북과 라와프 연주에 맞춰 빙글빙글 도는 위구르 전통춤은 모든 축제 분위기를 한층 더 밝게 만들어 줘요.'),
  'haikou/coconut': ('코코넛 시티', '거리마다 코코넛 야자수가 줄지어 서 있어 하이커우는 \'코코넛의 도시\'라는 별명을 얻게 되었어요.'),
  'haikou/arcade': ('치러우 거리', '남부 특유의 기둥이 있는 건축 양식인 \'치러우\' 건물들이 모여 그늘진 아케이드 거리를 형성하고 있어요.'),
  'haikou/crater': ('화산 공원', '도시 외곽에는 사화산 분화구가 푸른 녹지로 변모한 화산 지질 공원이 자리하고 있어요.'),
  'haikou/turtle': ('열대 바다', '따뜻하고 맑은 바닷물과 산호초가 어우러진 이곳 해안은 바다거북의 소중한 서식지예요.'),
  'luoyang/grotto': ('룽먼 석굴', '절벽에 새겨진 수만 개의 불상은 유네스코 세계문화유산으로 지정된 예술적 보물이에요.'),
  'luoyang/peony': ('모란의 도시', '매년 4월이면 수천 송이의 모란이 만개하여 뤄양을 \'모란의 도시\'로 물들여요.'),
  'luoyang/whitehorse': ('백마사', '서기 68년에 세워진 백마사는 중국 최초의 불교 사원으로 알려져 있어요.'),
  'luoyang/capital': ('고도', '13개 왕조의 수도였던 뤄양은 중국 문명의 발상지 중 하나예요.'),
  'shantou/gongfutea': ('쿵푸차', '작은 찻잔에 정성스럽게 우려내는 차오산 쿵푸차는 환대의 미학을 담은 예술이에요.'),
  'shantou/beefpot': ('소고기 훠궈', '신선한 소고기를 얇게 썰어 살짝 데쳐 먹는 차오산식 훠궈는 미식가들 사이에서 매우 유명해요.'),
  'shantou/opera': ('차오쥐', '600년의 역사를 자랑하는 차오쥐는 섬세한 노래와 화려한 자수 의상으로 잘 알려져 있어요.'),
  'shantou/harbor': ('산터우항', '수많은 화교의 고향인 이곳은 예로부터 해상 무역의 관문 역할을 해온 항구 도시예요.'),
  'baoding/mansion': ('직례총독부', '청나라 시대의 최고 지방 관청이었던 이곳은 보존 상태가 매우 뛰어난 행정 건물이에요.'),
  'baoding/donkeyburger': ('뤼러우훠사오', '바삭한 빵 사이에 매콤하게 양념한 당나귀 고기를 채워 넣은 이 지역의 대표적인 길거리 음식이에요.'),
  'baoding/balls': ('바오딩 철구', '손바닥 안에서 굴리며 손 운동을 하는 이 쇠공은 수백 년 동안 이어져 온 전통 건강법이에요.'),
  'baoding/reeds': ('바이양뎬', '화북 지역 최대의 습지인 이곳은 갈대와 연꽃이 어우러진 새들의 낙원이에요.'),
  'jilin/rime': ('지린 무송', '쑹화강변 나무에 하얗게 맺힌 상고대는 중국의 4대 자연 경관 중 하나로 꼽혀요.'),
  'jilin/snowboard': ('지린 스키장', '풍부한 적설량과 긴 시즌을 자랑하는 이곳은 북부 지역 최고의 스키 명소예요.'),
  'jilin/meteorite': ('지린 운석 박물관', '1976년에 떨어진 세계 최대 규모의 석질 운석이 이곳에 전시되어 있어요.'),
  'jilin/skate': ('쑹화강 빙상장', '겨울이 되면 꽁꽁 언 쑹화강은 스케이트를 타거나 산책을 즐기는 사람들로 가득해요.'),
  'ordos/khan': ('칭기즈칸 능', '초원의 영웅 칭기즈칸을 기리는 웅장한 능묘로, 몽골 문화의 중심지예요.'),
  'ordos/cashmere': ('오르도스 캐시미어', '오르도스 산 염소 털로 만든 캐시미어는 세계 섬유 시장에서 높은 명성을 얻고 있어요.'),
  'ordos/sanddune': ('샹사완', '모래 언덕을 타고 내려갈 때 소리가 나는 이곳은 쿠부치 사막에서 가장 인기 있는 여행지예요.'),
  'ordos/yurt': ('몽골식 게르', '끝없이 펼쳐진 초원 위에 세워진 하얀 펠트 천막인 게르는 유목민의 삶을 상징해요.'),
  'jining/confucius': ('공묘', '인근 취푸에 위치한 공자의 사당과 저택, 묘소는 유네스코 세계문화유산으로 지정되어 있어요.'),
  'jining/barge': ('징항 대운하', '베이징과 항저우를 잇는 운하의 주요 항구였던 지닝은 운하 문화의 중심지였어요.'),
  'jining/sword': ('양산박', '고전 소설 \'수호지\'에 등장하는 108명의 영웅들이 모여들었던 호수와 산악 지대예요.'),
  'jining/fishnet': ('웨이산호', '중국 북부에서 가장 큰 연꽃 호수로, 이곳 어부들은 여전히 전통적인 방식으로 그물을 던져 물고기를 잡아요.'),
  'langfang/culture': ('실크로드 문화센터', '실크로드의 다양한 예술과 문화를 한자리에서 만나볼 수 있는 현대적인 복합 문화 공간이에요.'),
  'langfang/furniture': ('샹허 가구단지', '인근 샹허 지역은 중국 최대 규모의 가구 생산 및 유통 거점 중 하나로 유명해요.'),
  'langfang/tunnel': ('고대 지하 군사 터널', '천 년의 역사를 간직한 지하 군사 터널로, 과거 국경 방어를 위해 구축된 흔적을 엿볼 수 있어요.'),
  'langfang/themepark': ('제1성 테마파크', '고대 성곽 도시를 재현해 놓은 거대한 테마파크로 가족 단위 여행객들이 즐겨 찾아요.'),
  'yancheng/salt': ('옌청', '지명 자체가 \'소금 성\'을 뜻하며, 수 세기 동안 중국의 주요 소금 생산지였던 곳이에요.'),
  'yancheng/crane': ('단정학', '이곳의 해안 습지는 야생 단정학이 겨울을 나는 세계 최대 규모의 서식지예요.'),
  'yancheng/elk': ('다비드사슴', '한때 야생에서 멸종되었던 다비드사슴이 이곳 습지에서 다시 번식하여 생태계를 회복했어요.'),
  'yancheng/wetland': ('해안 습지', '유네스코 세계자연유산으로 등재된 이곳 갯벌은 철새들의 중요한 중간 기착지예요.'),
  'huzhou/brush': ('후저우 붓', '중국 서예의 \'문방사우\' 중 하나로 꼽히는 명품 붓이 바로 이곳에서 만들어져요.'),
  'huzhou/bamboo': ('안지 죽림', '영화 촬영지로도 유명한 끝없이 펼쳐진 대나무 숲이 시원한 공기를 선사해요.'),
  'huzhou/silkworm': ('양잠', '타이후 호수 남쪽 기슭은 천 년 동안 이어져 온 비단 생산의 중심지예요.'),
  'huzhou/whitetea': ('안지 백차', '연한 잎 색깔과 은은한 단맛이 특징인 안지 백차는 중국에서 가장 귀한 차 중 하나예요.'),
  'quzhou/go': ('바둑', '난커산의 전설이 깃든 이곳은 바둑의 성지로 널리 알려져 있어요.'),
  'quzhou/peaks': ('장랑산', '하늘을 향해 솟아오른 세 개의 거대한 돌기둥이 유네스코 세계유산으로 지정된 독특한 풍경을 자아내요.'),
  'quzhou/ponkan': ('취저우 폰칸(만다린)', '껍질이 달콤한 폰칸 귤은 온화한 언덕이 겨울에 선사하는 귀한 선물이에요.'),
  'quzhou/cake': ('샤오빙(구운 납작빵)', '화덕 벽에 붙여 구워낸 바삭한 참깨 납작빵은 이곳의 대표적인 아침 식사 메뉴예요.'),
  'huainan/tofu': ('두부의 발상지', '2,000년 전 팔공산에서 처음 만들어진 두부는 이곳에서 시작되어 전 세계의 요리로 퍼져나갔어요.'),
  'huainan/coalmine': ('석탄 도시', '풍부한 석탄 매장량을 자랑하는 화이난은 중국 동부의 주요 에너지 기지예요.'),
  'huainan/oldtown': ('서우현 고성', '송나라 시대의 성벽이 온전히 보존된 이곳은 고대 방어 시설의 형태를 잘 보여주는 귀중한 유적이에요.'),
  'huainan/classic': ('회남자', '유안 왕이 편찬한 철학 고전인 \'회남자\'가 바로 이 땅에서 집필되었어요.'),
  'jingdezhen/porcelain': ('도자기의 수도', '천 년 동안 황실 도자기를 생산해 온 징더전은 세계적인 \'도자기의 수도\'로 불려요.'),
  'jingdezhen/kiln': ('고가마', '나무를 때어 불을 지피는 용 모양의 가마는 전통 도자기 제작 방식을 오늘날까지 이어오고 있어요.'),
  'jingdezhen/bluewhite': ('청화백자', '하얀 자기 위에 코발트색 안료로 그림을 그린 청화백자는 이 도시를 상징하는 세계적인 명물이에요.'),
  'jingdezhen/painting': ('도자기 회화', '장인들이 섬세한 붓으로 도자기에 그려 넣은 그림은 마치 훌륭한 예술 작품처럼 높은 가치를 인정받아요.'),
  'jian/jinggang': ('징강산', '안개 자욱한 이 산은 혁명의 첫 근거지로서 \'홍색 관광\'의 중심지예요.'),
  'jian/torch': ('혁명의 불꽃', '\'작은 불꽃 하나가 들판을 태울 수 있다\'는 말이 시작된 이곳은 역사적인 기념지예요.'),
  'jian/academy': ('바이루저우 서원', '간강의 섬 위에 세워진 천 년 역사의 서원은 수많은 과거 급제자를 배출했어요.'),
  'jian/pine': ('징강산 소나무', '안개를 뚫고 솟아오른 붉은 소나무는 산의 정신과 끈기를 상징해요.'),
  'nanping/wuyi': ('우이산', '붉은 절벽과 푸른 계곡이 어우러진 유네스코 세계유산으로, 자연과 문화의 보고라 불려요.'),
  'nanping/rocktea': ('암차', '절벽 바위틈에서 자란 우롱차인 \'대홍포\'는 세계에서 가장 비싼 차 중 하나예요.'),
  'nanping/bambooraft': ('구곡계 뗏목', '붉은 절벽 사이로 흐르는 구곡계에서 대나무 뗏목을 타고 유유자적하게 풍경을 감상할 수 있어요.'),
  'nanping/scholar': ('주희', '성리학을 집대성한 주희가 이 산 아래에서 제자들을 가르치며 학문을 닦았어요.'),
  'shenzhen/skyscraper': ('마천루', '40년 만에 작은 어촌에서 거대 도시로 변모한 선전의 마천루 숲은 중국 개혁개방의 기적을 상징해요.'),
  'shenzhen/chip': ('테크 시티', '화창베이 전자상가와 수많은 IT 기업이 모여 있는 선전은 \'중국의 실리콘밸리\'로 불려요.'),
  'shenzhen/miniature': ('세계지창', '세계 각국의 유명 랜드마크를 축소해 놓은 테마파크로, 선전을 대표하는 명소예요.'),
  'shenzhen/mangrove': ('선전만', '맹그로브 숲이 우거진 선전만은 철새와 백로들이 쉬어가는 평화로운 안식처예요.'),
  'xian/terracotta': ('병마용', '진시황릉을 지키는 수천 개의 흙 인형인 병마용은 세계 8대 불가사의로 꼽혀요.'),
  'xian/citywall': ('시안 성벽', '중국에서 가장 잘 보존된 명나라 시대 성벽으로, 자전거를 타고 성곽 위를 달리는 체험이 유명해요.'),
  'xian/drumtower': ('종루', '고대 수도 시안의 중심부에 위치한 명나라 시대의 종루는 도시의 심장부와 같아요.'),
  'xian/roujiamo': ('러우자모', '바삭한 빵 사이에 양념한 고기를 가득 채운 러우자모는 실크로드의 원조 햄버거라고 할 수 있어요.'),
  'suzhou/garden': ('졸정원', '기암괴석과 연못, 정자가 정교하게 어우러진 쑤저우의 정원들은 유네스코 세계유산으로 지정되어 있어요.'),
  'suzhou/watertown': ('수향마을', '운하와 돌다리, 하얀 집들이 어우러진 쑤저우는 \'동양의 베네치아\'라고 불려요.'),
  'suzhou/embroidery': ('쑤저우 자수', '천 년의 역사를 자랑하는 쑤저우 자수는 양면을 모두 수놓는 정교한 비단 공예예요.'),
  'suzhou/kunqu': ('쿤취', '중국 전통극의 어머니라 불리는 우아한 쿤취가 바로 이곳에서 탄생했어요.'),
  'kunming/stoneforest': ('스린', '수백만 년에 걸쳐 형성된 거대한 석회암 기둥들이 신비로운 돌 미로를 이루고 있어요.'),
  'kunming/springcity': ('춘성', '일 년 내내 온화한 기후를 자랑하는 쿤밍은 꽃이 지지 않는 \'봄의 도시\'예요.'),
  'kunming/seagull': ('붉은부리갈매기', '매년 겨울이면 시베리아에서 날아온 수천 마리의 갈매기가 호숫가를 하얗게 뒤덮어요.'),
  'kunming/ricenoodle': ('궈차오미셴', '뜨거운 육수에 쌀국수를 직접 넣어 먹는 궈차오미셴은 윈난성을 대표하는 별미예요.'),
  'jinan/spring': ('천성', '땅속에서 솟아오르는 72개의 유명한 샘 덕분에 지난은 \'샘의 도시\'라는 별명을 얻었어요.'),
  'jinan/daminglake': ('다밍후', '버드나무와 연꽃으로 둘러싸인 이 호수는 샘물에서 흘러나온 물로 채워져 있어요.'),
  'jinan/buddhamountain': ('첸포산', '산비탈에 수많은 불상이 새겨져 있어 많은 순례자가 찾는 성스러운 산이에요.'),
  'jinan/poet': ('리칭자오', '중국 역사상 가장 위대한 여성 시인으로 꼽히는 리칭자오가 바로 이 샘의 도시에서 태어났어요.'),
  'ningbo/library': ('톈이거', '450년의 역사를 자랑하는 톈이거는 아시아에서 가장 오래된 개인 도서관이에요.'),
  'ningbo/port': ('닝보-저우산항', '닝보-저우산항은 화물 처리량 기준으로 세계에서 가장 바쁜 항구예요.'),
  'ningbo/tangyuan': ('탕위안', '깨를 가득 채운 쫄깃한 찹쌀 경단인 탕위안은 이 도시를 대표하는 달콤한 간식이에요.'),
  'ningbo/seafood': ('해산물', '동중국해에서 잡은 조기와 게는 닝보 식탁에서 빠질 수 없는 핵심 재료예요.'),
  'shijiazhuang/bridge': ('자오저우교', '1,400년 된 이 돌다리는 세계에서 가장 오래된 개방형 아치교예요.'),
  'shijiazhuang/clifftemple': ('창옌산', '절벽 사이에 아슬아슬하게 걸쳐 있는 사찰 다리는 수많은 영화의 배경이 되었어요.'),
  'shijiazhuang/redbase': ('시바이포 혁명 유적지', '신중국 건설의 밑그림이 그려진 이곳은 중국의 대표적인 \'홍색 관광\' 명소예요.'),
  'shijiazhuang/pharma': ('제약 도시', '중국 최대 규모의 제약 회사들이 모여 있는 이곳은 항생제 생산의 중심지예요.'),
  'taiyuan/jincitemple': ('진사', '3천 년의 역사를 간직한 불상과 샘이 어우러진 진사는 화북 지역에서 가장 아름다운 사찰 정원이에요.'),
  'taiyuan/coalcart': ('석탄의 도시', '산시성의 풍부한 석탄 자원은 중국 경제의 원동력이며, 타이위안은 그 부의 중심지예요.'),
  'taiyuan/vinegar': ('라오천추(산시 식초)', '오랜 시간 숙성시킨 라오천추는 산시 요리의 깊은 맛을 내는 필수 식재료예요.'),
  'taiyuan/twinpagoda': ('쌍탑', '타이위안의 상징인 두 개의 팔각 명나라 시대 탑이 나란히 솟아 있어요.'),
  'hohhot/lamatemple': ('다자오 사원', '은불상으로 유명한 이 티베트 불교 사원은 후허하오터의 정신적 안식처예요.'),
  'hohhot/dairy': ('유제품의 도시', '중국 최대 유제품 브랜드들의 발상지인 이곳은 \'우유의 수도\'로 불려요.'),
  'hohhot/wrestling': ('몽골 씨름', '나담 축제의 하이라이트인 몽골 씨름은 초원 민족의 강인함을 보여주는 스포츠예요.'),
  'hohhot/prairie': ('초원', '도시 너머로 끝없이 펼쳐진 몽골 초원에서는 말과 가축 떼가 자유롭게 뛰놀아요.'),
  'sanya/resortbeach': ('야롱완 해변', '고운 모래사장과 에메랄드빛 바다가 펼쳐진 야롱완은 \'중국의 하와이\'라고 불려요.'),
  'sanya/guanyin': ('남산 해상 관음상', '바다 위로 108미터 높이로 솟아 있는 관음상은 세계에서 가장 높은 불상 중 하나예요.'),
  'sanya/diving': ('스쿠버 다이빙', '따뜻하고 맑은 바닷물과 산호초가 가득한 싼야는 다이빙을 즐기기에 최고의 장소예요.'),
  'sanya/coconutdrink': ('코코넛', '열대 과수원에서 갓 딴 신선한 코코넛 워터는 섬 여행의 더위를 식혀주는 최고의 음료예요.'),
  'yangzhou/slenderlake': ('서우시후(수서호)', '버드나무와 하얀 다리가 어우러진 서우시후는 한 폭의 동양화처럼 우아한 풍경을 자랑해요.'),
  'yangzhou/friedrice': ('양저우 볶음밥', '새우와 달걀을 넣어 황금빛으로 볶아낸 양저우 볶음밥은 세계적으로 유명한 요리예요.'),
  'yangzhou/morningtea': ('자오차', '딤섬과 차를 곁들여 우아하게 아침을 즐기는 것은 양저우의 대표적인 식문화예요.'),
  'yangzhou/gegarden': ('거원', '사계절의 변화를 돌로 표현한 대나무 정원인 거원은 중국 고전 조경의 걸작으로 꼽혀요.'),
  'weihai/navalisland': ('류궁도', '북양함대의 근거지였던 류궁도는 중국 근대 해군 역사의 발자취를 간직한 곳이에요.'),
  'weihai/swan': ('스완 레이크', '매년 겨울이면 시베리아에서 날아온 수백 마리의 큰고니가 해안 석호를 찾아와 장관을 이뤄요.'),
  'weihai/seacucumber': ('해삼', '차갑고 깨끗한 바다에서 자란 해삼은 웨이하이에서 가장 귀하게 여기는 해산물이에요.'),
  'weihai/cape': ('중국 동단', '중국에서 가장 동쪽에 위치한 이곳은 가장 먼저 아침 해를 맞이하는 곳으로 유명해요.'),
  'handan/taichi': ('태극권', '양식과 오식 태극권의 발상지인 광푸 고성은 태극권의 본고장이라 불려요.'),
  'handan/congtai': ('총대', '고대 조나라 시대부터 이어진 총대는 2천 년의 역사를 굽어보고 있는 유서 깊은 누대예요.'),
  'handan/idiom': ('성어의 도시', '1,500개가 넘는 중국 성어의 유래가 된 한단은 \'성어의 도시\'라는 별칭을 가지고 있어요.'),
  'handan/ciporcelain': ('자주요', '흰 바탕에 검은 무늬를 넣은 자주요 도자기는 중국 민간 도자기의 정수로 평가받아요.'),
  'daqing/oilpump': ('유전', '중국 최대 규모를 자랑하는 다칭 유전에는 쉼 없이 움직이는 펌프잭들이 끝없이 펼쳐져 있어요.'),
  'daqing/oilworker': ('철인', '석유 노동자 영웅 왕진희의 강인한 정신은 다칭이라는 도시를 세운 근간이 되었어요.'),
  'daqing/reedlake': ('습지', '유전 사이로 넓게 펼쳐진 갈대 습지는 두루미와 고니 같은 철새들의 보금자리예요.'),
  'daqing/hotspring': ('온천', '지하에서 솟아나는 따뜻한 온천수는 추운 북쪽 지방에서 몸과 마음을 녹여주는 휴식처가 되어줘요.'),
  'zibo/bbq': ('쯔보 바비큐', '작은 화로에 구운 꼬치를 얇은 전병에 싸 먹는 방식으로, 중국 전역에서 큰 인기를 끈 미식 문화예요.'),
  'zibo/cuju': ('추쥐', '세계에서 가장 오래된 축구 형태인 추쥐는 고대 제나라의 수도였던 린쯔에서 시작되었어요.'),
  'zibo/ceramic': ('쯔보 도자기', '천년의 역사를 간직한 가마가 있는 이곳은 중국 북부의 대표적인 도자기 생산지예요.'),
  'zibo/glass': ('류리', '색을 입힌 유리를 녹여 수작업으로 만드는 류리는 영롱한 빛을 내는 전통 공예품이에요.'),
  'taian/mounttai': ('태산', '오악 중 으뜸으로 꼽히는 태산은 황제들이 하늘에 제사를 지내던 가장 신성한 산이에요.'),
  'taian/sunrise': ('태산 일출', '구름 바다 위로 솟아오르는 태양을 감상하는 것은 태산 등반의 가장 큰 보람이에요.'),
  'taian/stonesteps': ('태산 돌계단', '정상까지 이어지는 7,000개의 돌계단은 순례자들에게는 체력과 인내심을 시험하는 길이에요.'),
  'taian/daitemple': ('다이묘', '태산 기슭에 자리한 웅장한 사찰로, 황제들이 태산 제사를 준비하며 머물던 곳이에요.'),
  'lianyungang/monkey': ('화과산', '서유기의 주인공 손오공의 고향으로 알려진 화과산이 바로 이곳에 있어요.'),
  'lianyungang/seaport': ('롄윈강항', '실크로드의 동쪽 해상 관문이자 유라시아 횡단 철도가 시작되는 태평양 연안의 항구예요.'),
  'lianyungang/mountain': ('윈타이산', '가파른 봉우리와 울창한 숲을 자랑하는 윈타이산은 장쑤성에서 가장 높은 산이에요.'),
  'lianyungang/crystal': ('수정의 고장', '인근의 둥하이 지역은 세계 최대 규모의 수정 시장이 형성되어 있는 곳으로 유명해요.'),
  'maanshan/libai': ('이백', '중국 최고의 시인으로 추앙받는 이백이 생을 마감하고 잠들어 있는 강변 도시예요.'),
  'maanshan/steel': ('철강 도시', '마강 제철소가 위치한 이곳은 중국의 주요 철강 산업 기지 중 하나로 성장했어요.'),
  'maanshan/rivercliff': ('채석기', '양쯔강으로 깎아지른 듯 솟아 있는 절벽으로, 시인 이백과 관련된 전설이 깃든 곳이에요.'),
  'maanshan/moonwine': ('이백의 달과 술', '이백의 시에 등장하는 달과 술은 오늘날에도 강변 축제에서 여전히 기념되고 있어요.'),
  'longyan/tulou': ('융딩 토루', '언덕 곳곳에 자리 잡은 거대한 원형의 객가인 요새 주택은 유네스코 세계문화유산으로 지정되어 있어요.'),
  'longyan/redmeeting': ('구톈 회의', '홍군의 방향을 결정지은 역사적인 회의가 바로 이 마을에서 열렸어요.'),
  'longyan/hakka': ('객가 문화', '북쪽에서 이주해 온 객가인들은 이곳 산악 지대에서 자신들만의 언어와 음식 문화를 이어가고 있어요.'),
  'longyan/mountain': ('관즈산', '붉은 절벽과 맑은 연못이 어우러진 이 산은 푸젠성 남부의 자연 보석이라 불려요.'),
  'sanming/danxia': ('타이닝 단샤 지형', '붉은 절벽과 협곡으로 이루어진 이 유네스코 세계지질공원은 마치 하늘에서 떨어진 돌들의 미로 같아요.'),
  'sanming/shaxian': ('사현 샤오츠', '저렴한 완탕과 비빔면으로 유명한 사현 샤오츠는 이제 중국 전역에서 즐겨 찾는 음식이 되었어요.'),
  'sanming/forest': ('녹색의 수도', '중국에서 가장 숲이 울창한 도시인 싼밍은 맑은 공기와 푸른 산으로 숨 쉬는 곳이에요.'),
  'sanming/goldenlake': ('진후', '단샤 절벽 사이로 길게 뻗은 이 호수는 배를 타고 유람하며 감상할 수 있어요.'),
  'ningde/mudflat': ('샤푸 갯벌', '바다와 함께 시시각각 변하는 샤푸의 반짝이는 갯벌은 세계에서 가장 사진 찍기 좋은 해안 중 하나예요.'),
  'ningde/whitetea': ('푸딩 백차', '솜털이 보송보송한 찻잎을 말려 만드는 푸딩 백차는 오래될수록 그 가치가 더욱 높아져요.'),
  'ningde/taimu': ('타이무산', '바다 위로 솟은 화강암 봉우리와 동굴이 어우러진 이 산은 \'바다 위의 선경\'이라 불려요.'),
  'ningde/croaker': ('조기', '잔잔한 만에서 양식되는 큰 조기는 이 도시를 대표하는 해산물 보물이에요.'),
  'shaoguan/redcliff': ('단샤산', '\'단샤 지형\'이라는 이름의 유래가 된 이 붉은 바위산은 독특한 모양의 암석 기둥으로 유명해요.'),
  'shaoguan/chantemple': ('남화사', '선종의 제6대 조사인 혜능 대사가 머물렀던 이 사찰은 선종의 성지로 꼽혀요.'),
  'shaoguan/ancestor': ('주지항', '수많은 남부 중국인의 조상이 이주해 온 뿌리 깊은 역사가 깃든 골목이에요.'),
  'shaoguan/yaodance': ('야오족', '산간 마을에 거주하는 야오족은 화려한 전통 의상과 독특한 북춤으로 잘 알려져 있어요.'),
  'zhanjiang/oyster': ('잔장 굴', '따뜻한 남쪽 바다에서 자라 통통하게 살이 오른 굴을 숯불에 구워 먹는 맛이 일품이에요.'),
  'zhanjiang/navy': ('해군 기지', '중국 남해 함대의 본거지이자 국가 남쪽 바다의 관문 역할을 하는 깊은 항구예요.'),
  'zhanjiang/mangrove': ('맹그로브 숲', '중국 최대 규모의 맹그로브 숲으로, 조수 간만의 차가 있는 바다에서 백로와 게들의 안식처가 되어주고 있어요.'),
  'zhanjiang/donghai': ('둥하이섬', '긴 해변과 적당한 바람 덕분에 일광욕과 서핑을 즐기려는 사람들로 항상 붐비는 곳이에요.'),
  'maoming/lychee': ('리치 산지', '중국 최대의 리치 생산지인 마오밍은 과거 황제에게 진상하던 리치가 나던 고장이에요.'),
  'maoming/refinery': ('석유화학 기지', '중국 남부 최대 규모의 정유 시설 중 하나가 자리 잡고 있어 도시 산업의 원동력이 되고 있어요.'),
  'maoming/ladyxian': ('선 부인', '남부 지역을 통합한 영웅 선 부인은 천 년이 넘는 세월 동안 현지인들에게 존경받고 있어요.'),
  'maoming/seaside': ('중국 제일 해변', '중국 최고의 해변이라 불리는 이곳은 가족 단위 여행객들이 황금빛 모래사장을 즐기기에 아주 좋아요.'),
  'zhaoqing/sevenstar': ('칠성암', '호수 위로 솟아오른 일곱 개의 석회암 바위산은 \'광둥의 구이린\'이라 불릴 만큼 아름다워요.'),
  'zhaoqing/inkstone': ('돤옌 벼루', '서예의 네 가지 보물 중 하나인 돤옌 벼루는 이곳에서 천 년 넘게 정성스럽게 제작되어 왔어요.'),
  'zhaoqing/dinghu': ('딩후산', '중국 최초의 자연보호구역으로, 울창한 열대우림과 폭포가 어우러져 살아있는 산소 카페 같은 곳이에요.'),
  'zhaoqing/songwall': ('송대 성벽', '송나라 시대의 모습을 온전히 간직한 성벽이 자오칭 옛 시가지를 둥글게 감싸고 있어요.'),
  'huizhou/westlake': ('후이저우 서호', '유배 생활을 했던 시인 소동파가 사랑한 이 호수는 버드나무와 제방이 어우러져 한 편의 시 같은 풍경을 자아내요.'),
  'huizhou/luofu': ('뤄푸산', '도교 수행자와 약초의 산으로 알려진 이곳은 \'남쪽의 첫 번째 명산\'으로 불립니다.'),
  'huizhou/alchemy': ('거홍의 연단술', '연단술사이자 의학자였던 거홍이 이 산에서 전통 의학의 기틀을 다졌습니다.'),
  'huizhou/xunliao': ('쉰랴오완', '맑은 바닷물과 부드러운 모래사장이 어우러진 남해안의 평화로운 휴양지입니다.'),
  'meizhou/weilongwu': ('객가 위룽우', '\'세계 객가의 수도\'라 불리는 메이저우는 말발굽 모양의 전통 가옥인 위룽우로 유명합니다.'),
  'meizhou/saltchicken': ('옌쥐지', '뜨거운 소금 속에 묻어 구워낸 객가식 닭 요리로, 육질이 매우 부드러운 것이 특징입니다.'),
  'meizhou/football': ('축구의 고향', '중국 축구의 요람으로 여겨지는 이 도시는 대대로 수많은 축구 스타를 배출했습니다.'),
  'meizhou/plum': ('매화', '도시 이름에 \'매화\'가 들어가는 만큼 겨울이 되면 도시 곳곳이 아름다운 매화로 가득 찹니다.'),
  'jiangmen/diaolou': ('카이핑 댜오러우', '해외 이주민들이 고향으로 돌아와 세운 다층 요새형 건축물로 유네스코 세계문화유산에 등재되었습니다.'),
  'jiangmen/qiaoxiang': ('화교의 고향', '수백만 화교들의 고향인 이곳은 동양과 서양의 문화가 조화롭게 어우러져 있습니다.'),
  'jiangmen/chenpi': ('천피', '신후이 지역에서 생산된 귤껍질을 오래 숙성시킨 것으로, 향신료이자 귀한 약재로 쓰입니다.'),
  'jiangmen/birds': ('냐오탕궈', '거대한 반얀나무 한 그루가 숲을 이루고 있으며, 수만 마리의 백로가 서식하고 있습니다.'),
  'yangjiang/knife': ('칼의 도시', '수백 년 전통의 대장간 기술을 바탕으로 중국 주방용 칼의 상당수가 이곳에서 생산됩니다.'),
  'yangjiang/shipwreck': ('난하이 1호', '해상 실크로드의 송나라 시대 침몰선이 수중 박물관에 보물들과 함께 전시되어 있습니다.'),
  'yangjiang/hailing': ('하이링다오', '햇살 가득한 해변과 파도가 매력적인 광둥성 최고의 해수욕장입니다.'),
  'yangjiang/kite': ('연의 도시', '웨이팡과 함께 중국의 양대 연 도시로 꼽히며, 가을 하늘을 화려한 연들이 수놓습니다.'),
  'qingyuan/rafting': ('칭위안 래프팅', '칭위안은 거센 산악 계곡이 많아 중국 래프팅의 본고장으로 불려요.'),
  'qingyuan/chicken': ('칭위안 닭요리', '뼈가 가늘고 풍미가 뛰어난 칭위안 토종닭은 광둥 식탁에서 가장 인기 있는 식재료예요.'),
  'qingyuan/hotspring': ('온천', '산골짜기에서 솟아나는 천연 온천수는 주말 휴양지로 큰 사랑을 받고 있어요.'),
  'qingyuan/yaoterrace': ('야오족 다랑논', '롄난 야오족이 산비탈을 깎아 만든 다랑논은 수백 년의 땀방울이 서린 계단식 논이에요.'),
  'chaozhou/guangjibridge': ('광지교', '배가 지나갈 수 있도록 중앙을 열고 닫을 수 있는 이 고대 다리는 중국 4대 명교 중 하나예요.'),
  'chaozhou/woodcarving': ('금박 목조각', '금박을 입힌 다층 목조각들이 사찰 내부를 화려하고 눈부시게 장식하고 있어요.'),
  'chaozhou/chaoxiu': ('차오저우 자수', '금실을 도톰하게 올리는 기법을 사용하는 차오저우 자수는 중국 남부에서 가장 화려하기로 유명해요.'),
  'chaozhou/kaiyuan': ('카이위안사', '1,200년의 역사를 간직한 당나라 양식의 고요한 사찰로, 도시의 정신적 중심지예요.'),
  'jieyang/citygate': ('진셴먼', '강 위에 우아하게 솟은 이 목조 성문은 옛 지에양의 모습을 간직한 상징적인 건축물이에요.'),
  'jieyang/jade': ('옥의 도시', '양메이 마을은 중국 최대 규모의 옥 조각 및 거래 중심지 중 하나예요.'),
  'jieyang/jieyanglou': ('지에양러우', '전통적인 처마 양식을 갖춘 이 거대한 누각은 차오산 문화를 상징하는 현대적인 기념물이에요.'),
  'jieyang/beefbroth': ('차오산 소고기탕', '맑은 육수에 신선한 소고기를 살짝 데쳐 먹는 이 요리는 이 지역의 대표적인 별미예요.'),
  'yunfu/marble': ('석재의 왕국', '대리석과 석재 가공의 중심지인 윈푸는 정교하게 다듬은 석재를 전 세계로 수출하고 있어요.'),
  'yunfu/patriarch': ('육조 혜능', '선종의 대가인 혜능 대사의 고향으로, 궈언사가 있어 더욱 성스러운 땅으로 여겨져요.'),
  'yunfu/tianlu': ('톈루산', '구름에 덮인 봉우리와 차밭이 어우러진 톈루산은 도시를 감싸는 푸른 왕관과 같아요.'),
  'yunfu/xijiang': ('시강', '중국 남부의 젖줄이자 주강의 본류인 시강이 도시를 가로질러 흐르고 있어요.'),
  'liuzhou/luosifen': ('뤄쓰펀', '특유의 톡 쏘는 향과 매콤새콤한 맛을 자랑하는 뤄쓰펀은 중국 전역에서 큰 인기를 끌고 있는 쌀국수 요리예요.'),
  'liuzhou/autocity': ('자동차 도시', '류저우는 시민들이 즐겨 타는 소형차를 중심으로 중국 최대의 자동차 생산 기지 중 하나로 자리 잡았어요.'),
  'liuzhou/karst': ('류저우 카르스트 지형', '도시를 감싸 안은 강줄기와 석회암 산봉우리들이 어우러져 산업 도시 류저우에 자연의 아름다움을 더해줘요.'),
  'liuzhou/liuhou': ('류쭝위안', '당나라 시대의 시인이자 류저우의 자사였던 류쭝위안을 기리는 사당이 시내 공원에 자리하고 있어요.'),
  'wuzhou/gemstone': ('보석의 도시', '전 세계에서 유통되는 인공 보석의 상당수가 이 강변 도시의 공방에서 가공되고 있어요.'),
  'wuzhou/liubaotea': ('류바오차', '오랫동안 숙성시킨 류바오차는 습한 남부 지방 사람들의 소화를 돕는 전통적인 차예요.'),
  'wuzhou/turtlejelly': ('귀령고', '쌉싸름한 맛이 특징인 검은색 한방 젤리 귀령고는 더운 날씨에 몸의 열을 식혀주는 별미예요.'),
  'wuzhou/dragonmother': ('용모묘', '강의 여신인 용모를 모시는 이 사당은 예로부터 강을 터전으로 살아온 사람들의 깊은 신앙심이 깃든 곳이에요.'),
  'beihai/silverbeach': ('인탄', '눈부시게 빛나는 고운 모래사장으로 유명한 \'천하제일탄\' 인탄이 끝없이 펼쳐져 있어요.'),
  'beihai/pearl': ('진주의 도시', '허푸의 남해 진주는 황실에 진상될 만큼 예로부터 최고의 품질로 인정받아 왔어요.'),
  'beihai/weizhou': ('웨이저우섬', '중국에서 가장 젊은 화산섬인 웨이저우섬은 검은 절벽과 산호초 덕분에 다이버들에게 인기가 많아요.'),
  'beihai/oldstreet': ('베이하이 라오제', '한 세기가 넘은 서양식 기둥 건물이 늘어선 이곳은 해상 실크로드 항구 도시의 옛 모습을 간직하고 있어요.'),
  'qinzhou/nixingpottery': ('니싱도기', '가마 안에서 스스로 색이 변하는 신비로운 니싱도기는 중국 4대 명도 중 하나로 꼽혀요.'),
  'qinzhou/dolphin': ('흰돌고래', '싼냥완에서 헤엄치는 희귀한 중국 흰돌고래는 친저우 시민들에게 가장 사랑받는 도시의 상징이에요.'),
  'qinzhou/oysterfarm': ('오이스터 랜드', '얕은 만에서 양식되는 거대한 굴 덕분에 친저우는 중국의 굴 생산지로 유명해요.'),
  'qinzhou/general': ('펑쯔차이 장군', '국경을 수호했던 노장 펑쯔차이 장군의 고향으로, 곳곳에 영웅적인 역사가 깃들어 있어요.'),
  'guigang/lotus': ('연꽃의 도시', '여름 내내 드넓은 연꽃밭이 만개하여 구이강은 \'연꽃의 도시\'라고 불려요.'),
  'guigang/uprising': ('진톈 봉기', '역사를 뒤흔든 태평천국 운동의 첫 불꽃이 바로 이곳에서 시작되었어요.'),
  'guigang/nanshan': ('난산사', '바위를 깎아 만든 천 년 역사의 동굴 사찰로, 황제의 친필 비석이 보존되어 있어요.'),
  'guigang/sugarcane': ('사탕수수', '비옥한 강 유역은 중국 최대의 설탕 생산을 가능하게 하는 달콤한 원천이에요.'),
  'yulin/medicine': ('한약재 시장', '중국 남부 최대 규모의 전통 약재 시장으로, 수천 가지의 치유 약초가 모여 있어요.'),
  'yulin/goldenpalace': ('윈톈궁', '금으로 장식된 거대한 문화 궁전으로, 웅장한 조각상과 화려한 전각이 방문객을 압도해요.'),
  'yulin/lychee': ('리치 과수원', '따뜻한 언덕에서 자란 달콤한 리치는 여름 시장을 붉게 물들이는 보물이에요.'),
  'yulin/beef': ('위린 소고기', '향신료로 맛을 낸 \'뉴바\' 소고기는 이 지역의 오랜 전통 간식이에요.'),
  'baise/redbase': ('바이서 봉기', '젊은 덩샤오핑이 이끈 봉기로, 중국 현대사의 중요한 전환점이 된 곳이에요.'),
  'baise/sinkhole': ('러예 싱크홀', '세계 최대 규모의 거대한 싱크홀 군락으로, 그 깊은 곳에는 울창한 숲이 숨겨져 있어요.'),
  'baise/mango': ('망고의 수도', '뜨거운 계곡 지형 덕분에 바이서는 중국 최대의 망고 생산지로 자리 잡았어요.'),
  'baise/aluminum': ('알루미늄 도시', '보크사이트가 풍부하여 중국 남부 알루미늄 산업의 핵심 기지 역할을 하고 있어요.'),
  'hechi/longevity': ('바마 장수촌', '백 세가 넘는 장수 노인들이 많이 거주하는 바마는 세계적으로 유명한 \'장수의 고향\'이에요.'),
  'hechi/folksong': ('류삼저', '노래의 요정 류삼저의 전설은 오늘날까지도 주고받는 형식의 민요 대결로 이어지고 있어요.'),
  'hechi/bronzedrum': ('동고', '좡족과 산악 민족의 신성한 악기인 동고가 이곳에 가장 많이 보존되어 있어요.'),
  'hechi/geopark': ('카르스트 지질공원', '싱크홀과 동굴, 지하 강이 어우러진 이곳은 카르스트 지형의 신비로운 자연을 보여줘요.'),
  'laibin/sugarcity': ('설탕의 도시', '끝없이 펼쳐진 사탕수수 밭 덕분에 라이빈은 중국의 \'설탕 도시\'로 불려요.'),
  'laibin/yao': ('다야오산 야오족', '진슈 다야오산에 거주하는 다섯 갈래의 야오족은 귀중한 문화적 자산이에요.'),
  'laibin/hongshui': ('훙수이허', '웅장한 훙수이허 강은 계곡을 따라 흐르며 댐과 아름다운 경치를 선사해요.'),
  'laibin/shengtang': ('성탕산', '운해와 폭포가 장관을 이루는 성탕산은 다야오산맥에서 가장 높은 봉우리예요.'),
  'chongzuo/waterfall': ('더톈 폭포', '베트남 국경에 위치한 더톈 폭포는 아시아에서 가장 큰 국경 폭포예요.'),
  'chongzuo/langur': ('흰머리랑구르', '이곳 석회암 언덕에만 서식하는 희귀한 흰머리랑구르는 세계에서 가장 멸종 위기에 처한 원숭이 중 하나예요.'),
  'chongzuo/rockart': ('화산 암각화', '2,000년 전 쭤장 절벽에 그려진 붉은 인물화들은 유네스코 세계문화유산으로 등재되어 있어요.'),
  'chongzuo/borderpass': ('우의관', '베트남으로 향하는 역사적인 국경 관문으로, 남쪽 실크로드의 육로 통로 역할을 했어요.'),
  'beijing/great-wall': ('만리장성', '중국 북부 국경을 지키기 위해 수세기에 걸쳐 쌓은 세계에서 가장 긴 성벽으로, 베이징 근교의 바다링 장성이 가장 유명해요.'),
  'beijing/temple': ('천단공원', '명·청 시대 황제들이 풍년을 기원하며 하늘에 제사를 지내던 곳으로, 못을 사용하지 않은 3층 원형 지붕이 건축미의 정수로 꼽혀요.'),
  'beijing/pagoda': ('톈닝사 탑', '요나라 시대에 세워진 13층 벽돌 탑으로, 베이징의 천 년 역사를 간직한 가장 오래된 건축물 중 하나예요.'),
  'beijing/opera': ('경극', '노래, 대사, 무술, 곡예가 어우러진 200년 전통의 종합 예술로, 배우의 얼굴에 그려진 화장(롄푸)을 통해 인물의 성격을 알 수 있어요.'),
};
